siddhiQuery:
FROM RequestStream
SELECT apiContext, apiVersion, (apiContext == '/products/5g-network-monetization/v1' or apiContext == '/network/slices/1.0.0' or apiContext == '/events/network-events/1.0.0') AS isEligible, str:concat(apiContext,':',apiVersion) as throttleKey
INSERT INTO EligibilityStream;

FROM EligibilityStream[isEligible==true]#throttler:timeBatch(1 min)
SELECT throttleKey, (count(throttleKey) >= 120) as isThrottled, expiryTimeStamp group by throttleKey
INSERT ALL EVENTS into ResultStream;

FROM RequestStream
SELECT appId, apiContext, apiVersion, (apiContext == '/products/open-gateway-fraud-defense/v1' or apiContext == '/open-gateway/sim-swap-risk/1.0.0' or apiContext == '/open-gateway/number-verification/1.0.0') AS isEligible, str:concat(appId,':',apiContext,':',apiVersion) as throttleKey
INSERT INTO EligibilityStream;

FROM EligibilityStream[isEligible==true]#throttler:timeBatch(1 min)
SELECT throttleKey, (count(throttleKey) >= 60) as isThrottled, expiryTimeStamp group by throttleKey
INSERT ALL EVENTS into ResultStream;
